#include<cstdio>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res; 
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline bool Chkmin(T&x,const T&w){return w<x?x=w,true:false;}
template<typename T> inline bool Chkmax(T&x,const T&w){return x<w?x=w,true:false;}
template<typename T> inline void chkmin(T&x,const T&w){w<x?x=w:T();}
template<typename T> inline void chkmax(T&x,const T&w){x<w?x=w:T();}
const int N=1e5+10;int n,s,d,a[N],P[N],p;LL ans=0;
inline int bnd(const int &k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
struct node{int l,r,sz;LL sm;}t[N<<5];int Rt[N],cnt;
inline void update(const int &x){t[x].sm=t[t[x].l].sm+t[t[x].r].sm;t[x].sz=t[t[x].l].sz+t[t[x].r].sz;}
inline void add(int cur,int &x,const int &pos,const int &l=1,const int &r=p)
{
	t[x=++cnt]=t[cur];if(l==r){++t[x].sz;t[x].sm+=P[l];return;} const int &mid=(l+r)>>1;
	pos<=mid?add(t[cur].l,t[x].l,pos,l,mid):add(t[cur].r,t[x].r,pos,mid+1,r);update(x);
}
inline LL qry(const int &rl,const int &rr,const int &k,const int &l=1,const int &r=p)
{
	if(l==r)return 1ll*min(k,t[rr].sz-t[rl].sz)*P[l];const int &rsz=t[t[rr].r].sz-t[t[rl].r].sz,&mid=(l+r)>>1;
	return rsz<k?qry(t[rl].l,t[rr].l,k-rsz,l,mid)+t[t[rr].r].sm-t[t[rl].r].sm:qry(t[rl].r,t[rr].r,k,mid+1,r);
}
inline LL Qry(const int &l,const int &r){return qry(Rt[l-1],Rt[r],d-(r+r-s-l));}
inline void Solve(const int &l1,const int &r1,const int &l2,const int &r2)
{
	if(l1>r1)return;if(l2==r2){rep(l1,r1,i)chkmax(ans,Qry(i,l2));return;}
	const int &mid=(l1+r1)>>1;int idx=l2;LL mx=Qry(mid,l2);rep(l2+1,r2,i)if(Chkmax(mx,Qry(mid,i)))idx=i;
	chkmax(ans,mx);Solve(l1,mid-1,l2,idx);Solve(mid+1,r1,idx,r2);
}
inline void work()
{
	rep(1,n,i)add(Rt[i-1],Rt[i],a[i]);
	rep(1,s,i)chkmax(ans,Qry(i,s));Solve(1,s,s,n);
	memset(Rt,0,(n+3)<<2);cnt=0;
}
int main()
{
	n=read();s=read()+1;d=read();rep(1,n,i)a[i]=P[i]=read();
	std::sort(P+1,P+n+1);p=std::unique(P+1,P+n+1)-P-1;rep(1,n,i)a[i]=bnd(a[i]);
	work();s=n-s+1;for(int i=1;i<=(n>>1);++i){int tmp=a[i];a[i]=a[n-i+1];a[n-i+1]=tmp;} work();
	printf("%lld\n",ans);return 0;
}
